import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TranscriptionState {
  status: 'idle' | 'reading' | 'uploading' | 'transcribing' | 'completed' | 'error';
  text: string;
  error?: string;
}

export interface FileData {
  file: File;
  previewUrl?: string;
  base64Data?: string;
  mimeType?: string;
}

export enum TranscriptionModel {
  FAST = 'gemini-3-flash-preview',
  QUALITY = 'gemini-3-pro-preview'
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { TranscriptionModel } from "../types";

export const transcribeMedia = async (
  base64Data: string,
  mimeType: string,
  onChunk: (text: string) => void,
  modelName: string = TranscriptionModel.QUALITY
): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // We use the stream method to provide feedback during the potentially long process
    const responseStream = await ai.models.generateContentStream({
      model: modelName,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
          {
            text: "Please transcribe the attached media file following the system instructions.",
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.2, // Low temperature for more faithful transcription
      },
    });

    let fullText = "";

    for await (const chunk of responseStream) {
      const c = chunk as GenerateContentResponse;
      const text = c.text;
      if (text) {
        fullText += text;
        onChunk(fullText);
      }
    }

    return fullText;
  } catch (error: any) {
    console.error("Gemini Transcription Error:", error);
    throw new Error(error.message || "Failed to transcribe media.");
  }
};

import React, { useCallback, useState } from 'react';
import { FileData } from '../types';
import { MAX_FILE_SIZE_BYTES, WARNING_FILE_SIZE_BYTES } from '../constants';

interface FileUploadProps {
  onFileSelect: (data: FileData) => void;
  disabled: boolean;
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, disabled }) => {
  const [dragActive, setDragActive] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const processFile = useCallback((file: File) => {
    setError(null);

    if (file.size > MAX_FILE_SIZE_BYTES) {
      setError(`File size exceeds the 400MB limit. (${(file.size / (1024 * 1024)).toFixed(1)}MB)`);
      return;
    }

    const reader = new FileReader();

    reader.onload = (e) => {
      const result = e.target?.result as string;
      // result is "data:mime/type;base64,....."
      // we need to extract the base64 part and the mime type
      const [metadata, base64Data] = result.split(',');
      const mimeType = metadata.match(/:(.*?);/)?.[1];

      if (base64Data && mimeType) {
         onFileSelect({
          file,
          previewUrl: URL.createObjectURL(file),
          base64Data,
          mimeType
        });
      } else {
        setError("Failed to parse file data.");
      }
    };

    reader.onerror = () => {
      setError("Error reading file.");
    };

    reader.readAsDataURL(file);
  }, [onFileSelect]);

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  }, [processFile]);

  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
    }
  }, [processFile]);

  return (
    <div className="w-full">
      <div
        className={`relative group border-2 border-dashed rounded-2xl p-12 transition-all duration-300 ease-in-out text-center ${
          dragActive 
            ? 'border-indigo-500 bg-indigo-50' 
            : disabled 
              ? 'border-slate-200 bg-slate-50 cursor-not-allowed' 
              : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50 cursor-pointer'
        }`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={!disabled ? handleDrop : undefined}
      >
        <input
          id="file-upload"
          type="file"
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer disabled:cursor-not-allowed"
          onChange={handleChange}
          accept="audio/*,video/*"
          disabled={disabled}
        />

        <div className="flex flex-col items-center justify-center space-y-4 pointer-events-none">
          <div className={`p-4 rounded-full ${dragActive ? 'bg-indigo-100' : 'bg-slate-100'}`}>
            <svg className={`w-8 h-8 ${dragActive ? 'text-indigo-600' : 'text-slate-400'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v-11m0 0l-4 4m4-4l4 4" />
            </svg>
          </div>
          <div>
            <p className="text-lg font-medium text-slate-700">
              <span className="text-indigo-600">Click to upload</span> or drag and drop
            </p>
            <p className="text-sm text-slate-500 mt-1">Audio or Video (MP3, WAV, MP4, MOV)</p>
            <p className="text-xs text-slate-400 mt-2">Up to 1 hour / 400MB</p>
          </div>
        </div>
      </div>

      {error && (
        <div className="mt-4 p-4 bg-red-50 text-red-700 rounded-xl flex items-start">
           <svg className="w-5 h-5 mr-3 mt-0.5 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          <span className="text-sm font-medium">{error}</span>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { TranscriptionState } from '../types';

interface TranscriptViewProps {
  state: TranscriptionState;
}

export const TranscriptView: React.FC<TranscriptViewProps> = ({ state }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(state.text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    const element = document.createElement("a");
    const file = new Blob([state.text], { type: 'text/plain' });
    element.href = URL.createObjectURL(file);
    element.download = "transcription.txt";
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  if (state.status === 'idle' || state.status === 'reading') {
    return null;
  }

  return (
    <div className="w-full bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-[600px]">
      <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
        <div className="flex items-center space-x-2">
          <div className={`w-2 h-2 rounded-full ${state.status === 'transcribing' ? 'bg-amber-400 animate-pulse' : state.status === 'error' ? 'bg-red-500' : 'bg-green-500'}`} />
          <h2 className="text-sm font-semibold text-slate-700 uppercase tracking-wide">
            {state.status === 'transcribing' ? 'Transcribing...' : state.status === 'error' ? 'Error' : 'Transcript'}
          </h2>
        </div>

        <div className="flex space-x-2">
           <button 
            onClick={handleCopy}
            disabled={!state.text}
            className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors disabled:opacity-50"
            title="Copy to clipboard"
          >
            {copied ? (
               <svg className="w-5 h-5 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
            ) : (
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 012-2h2a2 2 0 012 2m-6 0h6" />
              </svg>
            )}
          </button>
          <button 
            onClick={handleDownload}
            disabled={!state.text}
            className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors disabled:opacity-50"
            title="Download .txt"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
            </svg>
          </button>
        </div>
      </div>

      <div className="flex-1 p-6 overflow-y-auto custom-scrollbar bg-white">
        {state.error ? (
           <div className="flex flex-col items-center justify-center h-full text-center text-red-500">
             <svg className="w-12 h-12 mb-4 opacity-50" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
             </svg>
             <p className="max-w-md">{state.error}</p>
           </div>
        ) : state.text ? (
          <div className="prose prose-slate max-w-none whitespace-pre-wrap leading-relaxed">
            {state.text}
            {state.status === 'transcribing' && (
              <span className="inline-block w-2 h-4 ml-1 align-middle bg-indigo-500 animate-pulse"></span>
            )}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center h-full text-slate-300">
             <svg className="w-16 h-16 mb-4 opacity-50" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v-11m0 0l-4 4m4-4l4 4" />
            </svg>
            <p>Ready to transcribe</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { FileUpload } from './components/FileUpload';
import { TranscriptView } from './components/TranscriptView';
