import { transcribeMedia } from './services/geminiService';
import { WARNING_FILE_SIZE_BYTES } from './constants';

const App: React.FC = () => {
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [transcriptionState, setTranscriptionState] = useState<TranscriptionState>({
    status: 'idle',
    text: '',
  });
  const [model, setModel] = useState<TranscriptionModel>(TranscriptionModel.QUALITY);

  // Ref to track if unmounted
  const isMounted = useRef(true);
  useEffect(() => {
    return () => { isMounted.current = false; };
  }, []);

  const handleFileSelect = (data: FileData) => {
    setFileData(data);
    setTranscriptionState({ status: 'idle', text: '' });
  };

  const handleReset = () => {
    setFileData(null);
    setTranscriptionState({ status: 'idle', text: '' });
  };

  const startTranscription = async () => {
    if (!fileData || !fileData.base64Data || !fileData.mimeType) return;

    setTranscriptionState({ status: 'transcribing', text: '' });

    try {
      await transcribeMedia(
        fileData.base64Data,
        fileData.mimeType,
        (partialText) => {
          if (isMounted.current) {
            setTranscriptionState(prev => ({ ...prev, text: partialText }));
          }
        },
        model
      );

      if (isMounted.current) {
        setTranscriptionState(prev => ({ ...prev, status: 'completed' }));
      }
    } catch (error: any) {
      if (isMounted.current) {
        setTranscriptionState(prev => ({ 
          ...prev, 
          status: 'error', 
          error: error.message || 'An unknown error occurred' 
        }));
      }
    }
  };

  const isTranscribing = transcriptionState.status === 'transcribing';

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 p-4 md:p-8 lg:p-12">
      <div className="max-w-6xl mx-auto space-y-8">

        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-3xl md:text-4xl font-bold text-slate-900 tracking-tight">
              Verba<span className="text-indigo-600">Flow</span>
            </h1>
            <p className="text-slate-500 mt-2 text-lg">
              Bilingual Speech-to-Text Transcription
            </p>
          </div>

          <div className="flex items-center space-x-4 bg-white p-1 rounded-xl border border-slate-200 shadow-sm">
             <button
              onClick={() => setModel(TranscriptionModel.FAST)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                model === TranscriptionModel.FAST 
                ? 'bg-indigo-50 text-indigo-700 shadow-sm' 
                : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Flash (Fast)
            </button>
            <button
              onClick={() => setModel(TranscriptionModel.QUALITY)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                model === TranscriptionModel.QUALITY 
                ? 'bg-indigo-50 text-indigo-700 shadow-sm' 
                : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Pro (Quality)
            </button>
          </div>
        </header>

        {/* Main Content */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Input */}
          <div className="lg:col-span-5 space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-semibold text-slate-800">Media Input</h3>
                {fileData && (
                  <button 
                    onClick={handleReset}
                    disabled={isTranscribing}
                    className="text-xs text-red-500 hover:text-red-700 font-medium disabled:opacity-50"
                  >
                    Remove File
                  </button>
                )}
              </div>

              {!fileData ? (
                <FileUpload onFileSelect={handleFileSelect} disabled={isTranscribing} />
              ) : (
                <div className="space-y-4">
                  {/* File Preview Card */}
                  <div className="relative overflow-hidden rounded-xl border border-slate-200 bg-slate-50">
                    <div className="aspect-video bg-black flex items-center justify-center">
                      {fileData.mimeType?.startsWith('video/') ? (
                         <video 
                           src={fileData.previewUrl} 
                           controls 
                           className="w-full h-full object-contain" 
                         />
                      ) : (
                        <div className="flex flex-col items-center justify-center text-slate-400">
                          <svg className="w-16 h-16 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" />
                          </svg>
                          <span className="text-sm font-medium">Audio File</span>
                        </div>
                      )}
                    </div>
                    <div className="p-3 bg-white border-t border-slate-100">
                      <p className="font-medium text-slate-700 truncate">{fileData.file.name}</p>
                      <p className="text-xs text-slate-500 mt-1">
                        {(fileData.file.size / (1024 * 1024)).toFixed(2)} MB • {fileData.mimeType}
                      </p>
                      {fileData.file.size > WARNING_FILE_SIZE_BYTES && (
                        <div className="mt-2 text-xs text-amber-600 bg-amber-50 p-2 rounded border border-amber-100">
                          Large file detected. Browser memory usage may be high.
                        </div>
                      )}
                    </div>
                  </div>

                  <button
                    onClick={startTranscription}
                    disabled={isTranscribing}
                    className={`w-full py-3.5 px-4 rounded-xl font-semibold text-white shadow-md transition-all transform active:scale-[0.98] flex items-center justify-center space-x-2 ${
                      isTranscribing 
                        ? 'bg-slate-400 cursor-not-allowed' 
                        : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-lg'
                    }`}
                  >
                    {isTranscribing ? (
                      <>
                        <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <span>Processing...</span>
                      </>
                    ) : (
                      <>
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v-11m0 0l-4 4m4-4l4 4" />
                        </svg>
                        <span>Start Transcription</span>
                      </>
                    )}
                  </button>
                </div>
              )}
            </div>

            <div className="bg-indigo-900 rounded-2xl p-6 text-white shadow-lg overflow-hidden relative">
              <div className="absolute top-0 right-0 -mr-4 -mt-4 w-24 h-24 bg-white/10 rounded-full blur-2xl"></div>
              <h3 className="font-semibold text-lg mb-2 relative z-10">Pro Tips</h3>
              <ul className="text-indigo-100 text-sm space-y-2 relative z-10 list-disc list-inside">
                <li>Best for clear audio with distinct speakers.</li>
                <li>Supports mixed languages in one sentence.</li>
                <li>Processing time is roughly 10-20% of duration.</li>
                <li>Keep browser tab open while processing.</li>
              </ul>
            </div>
          </div>

          {/* Right Column: Output */}
          <div className="lg:col-span-7">
            <TranscriptView state={transcriptionState} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

